DROP TRIGGER IF EXISTS tbiu_sc_kep_t_monthly_r_det ON sc_kep_t_monthly_receive_det CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_kep_t_monthly_r_det() RETURNS trigger AS $BODY$
BEGIN

  if coalesce(NEW.receive_seq::text, '') = '' or NEW.receive_seq = 0 then
    select max(receive_seq) into STRICT NEW.receive_seq
    from sc_kep_t_monthly_receive_det
    where membership_no = NEW.membership_no
    and receive_year = NEW.receive_year
    and receive_month = NEW.receive_month
    and seq_no = NEW.seq_no;

    if NEW.receive_seq > 0 then
      NEW.receive_seq := NEW.receive_seq + 1;
    else
      NEW.receive_seq := 1;
    end if;
  end if;

--spa_dberror('No 18/08/2020');
  if coalesce(NEW.unkeep_return::text, '') = '' then NEW.unkeep_return :=0;end if;
  if coalesce(NEW.unkeep_principal_of_loan::text, '') = '' then NEW.unkeep_principal_of_loan :=0;end if;
  if coalesce(NEW.unkeep_interest::text, '') = '' then NEW.unkeep_interest :=0;end if;
  if coalesce(NEW.unkeep_money_amount::text, '') = '' then NEW.unkeep_money_amount :=0;end if;
  if coalesce(NEW.user_adding::text, '') = '' then NEW.user_adding :='0';end if;

  --Niorn 2020-07-28 ไม่มียอดเงิน ให้ posting_status เป็น 1 
  --Niorn krabi 2021-03-11 รายการภายใน ที่งดเก็บ สถานะให้เป็น 0 เพื่อให้ทำรายการ PM ** เปลี่ยน คอนเซป จากเดิมไม่ยิง statement เปลี่ยนมายิง แล้วระบุหมวยเหตุว่า เป็นการงดงวดที่เท่าไหร่
--  if :new.money_amount = 0  then :new.posting_status :='1';end if;
  
  if NEW.ukpaid_agent_p = 0  then NEW.ukpaid_agent_p :=0;end if;
  if NEW.ukpaid_agent_i = 0  then NEW.ukpaid_agent_i :=0;end if;
  if NEW.ukpaid_agent_a = 0  then NEW.ukpaid_agent_a :=0;end if;
  if NEW.ukpaid_after_p = 0  then NEW.ukpaid_after_p :=0;end if;
  if NEW.ukpaid_after_i = 0  then NEW.ukpaid_after_i :=0;end if;
  if NEW.ukpaid_after_a = 0  then NEW.ukpaid_after_a :=0;end if;


--Niorn POT 2024-04-39
  if coalesce(NEW.principal_of_loan::text, '') = '' then NEW.principal_of_loan :=0;end if;
  if coalesce(NEW.interest::text, '') = '' then NEW.interest :=0;end if;
  if coalesce(NEW.money_amount::text, '') = '' then NEW.money_amount :=0;end if;
  if coalesce(NEW.principal_balance_of_loan::text, '') = '' then NEW.principal_balance_of_loan :=0;end if;
  if coalesce(NEW.intarr_pay::text, '') = '' then NEW.intarr_pay :=0;end if;
  if coalesce(NEW.principal_not::text, '') = '' then NEW.principal_not :=0;end if;
  if coalesce(NEW.interest_not::text, '') = '' then NEW.interest_not :=0;end if;
  if coalesce(NEW.money_amount_not::text, '') = '' then NEW.money_amount_not :=0;end if;
  if coalesce(NEW.mpost_money_amount::text, '') = '' then NEW.mpost_money_amount :=0;end if;
  if coalesce(NEW.money_return::text, '') = '' then NEW.money_return :=0;end if;
  if coalesce(NEW.mproc_principal_of_loan::text, '') = '' then NEW.mproc_principal_of_loan :=0;end if;
  if coalesce(NEW.mproc_interest::text, '') = '' then NEW.mproc_interest :=0;end if;
  if coalesce(NEW.unkeep_principal_of_loan::text, '') = '' then NEW.unkeep_principal_of_loan :=0;end if;
  if coalesce(NEW.unkeep_interest::text, '') = '' then NEW.unkeep_interest :=0;end if;
  if coalesce(NEW.unkeep_money_amount::text, '') = '' then NEW.unkeep_money_amount :=0;end if;
  if coalesce(NEW.mpost_principal_of_loan::text, '') = '' then NEW.mpost_principal_of_loan :=0;end if;
  if coalesce(NEW.mpost_interest::text, '') = '' then NEW.mpost_interest :=0;end if;

  
  if coalesce(NEW.posting_status::text, '') = '' then NEW.posting_status :='0';end if;

 
--  if :new.receive_seq = 5 then
--   spa_dberror( 'X24') ;
--  end if ;
RETURN NEW;
end
